# <div>Building a Dark Mode </div> Toggle with Context and localStorage

Every app needs dark mode now. Users expect it. Your eyes beg for it at 2 AM.

But implementing it poorly means flashing light mode before dark mode loads. Here's how to do it right.

---

## <div>The Problem:</div> The Flash of Light

```typescript
// Naive approach - causes flash
const App = () => {
  const [theme, setTheme] = useState('light'); // Starts light always

  useEffect(() => {
    const saved = localStorage.getItem('theme');
    if (saved) setTheme(saved); // Too late - already rendered light
  }, []);

  return <div className={theme}>{/* app */}</div>;
};
```

User sees light mode for a split second before dark loads. Jarring. Unprofessional.

---

## Step 1: Theme Context with TypeScript

```typescript
import { createContext, useContext, useEffect, useState } from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
  setTheme: (theme: Theme) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider = ({ children }: { children: React.ReactNode }) => {
  const [theme, setTheme] = useState<Theme>(() => {
    // Check localStorage first
    const saved = localStorage.getItem('theme') as Theme;
    if (saved) return saved;

    // Then check system preference
    if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
      return 'dark';
    }

    // Default to light
    return 'light';
  });

  useEffect(() => {
    localStorage.setItem('theme', theme);

    // Update document class for Tailwind
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within ThemeProvider');
  }
  return context;
};
```

---

## Step 2: Preventing Flash with Script Injection

The key: set theme BEFORE React hydrates:

```html
<!-- index.html -->
<!DOCTYPE html>
<html lang="en">
  <head>
    <script>
      // Runs before React loads
      (function () {
        const theme = localStorage.getItem("theme");
        const systemDark = window.matchMedia(
          "(prefers-color-scheme: dark)",
        ).matches;

        if (theme === "dark" || (!theme && systemDark)) {
          document.documentElement.classList.add("dark");
        } else {
          document.documentElement.classList.remove("dark");
        }
      })();
    </script>
  </head>
  <body>
    <div id="root"></div>
  </body>
</html>
```

Zero flash. Perfect.

---

## Step 3: Theme Toggle Component

```typescript
import { useTheme } from './ThemeContext';
import { Sun, Moon } from 'lucide-react';

export const ThemeToggle = () => {
  const { theme, toggleTheme } = useTheme();

  return (
    <button
      onClick={toggleTheme}
      className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition"
      aria-label="Toggle theme"
    >
      {theme === 'light' ? (
        <Moon className="w-5 h-5" />
      ) : (
        <Sun className="w-5 h-5" />
      )}
    </button>
  );
};
```

---

## Step 4: Tailwind Configuration

```javascript
// tailwind.config.js
module.exports = {
  darkMode: "class", // Use class strategy, not media query
  content: ["./src/**/*.{js,jsx,ts,tsx}"],
  theme: {
    extend: {
      colors: {
        // Your custom colors
      },
    },
  },
};
```

Now use dark mode in components:

```typescript
const Card = () => {
  return (
    <div className="bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100">
      <h2 className="text-gray-900 dark:text-white">Title</h2>
      <p className="text-gray-600 dark:text-gray-300">Content</p>
    </div>
  );
};
```

---

## Step 5: System Preference Detection

```typescript
// Listen for system theme changes
useEffect(() => {
  const mediaQuery = window.matchMedia("(prefers-color-scheme: dark)");

  const handleChange = (e: MediaQueryListEvent) => {
    // Only update if user hasn't manually set preference
    if (!localStorage.getItem("theme")) {
      setTheme(e.matches ? "dark" : "light");
    }
  };

  mediaQuery.addEventListener("change", handleChange);
  return () => mediaQuery.removeEventListener("change", handleChange);
}, []);
```

---

## Complete Usage

```typescript
// App.tsx
import { ThemeProvider } from './contexts/ThemeContext';
import { ThemeToggle } from './components/ThemeToggle';

function App() {
  return (
    <ThemeProvider>
      <div className="min-h-screen bg-white dark:bg-gray-900">
        <header className="p-4 border-b dark:border-gray-700">
          <ThemeToggle />
        </header>
        <main>{/* Your app */}</main>
      </div>
    </ThemeProvider>
  );
}
```

---

## Key Takeaways

1. **Inject script in HTML** to prevent flash of wrong theme
2. **Use class-based dark mode** (not media query) for manual control
3. **Respect system preferences** but let users override
4. **Persist choice** in localStorage
5. **Provide toggle** with clear visual feedback

Dark mode isn't just a feature it's expected. Build it right once, and users will thank you at 3 AM.

