## Handling Connection Drops Gracefully

Networks fail. Users move between WiFi and cellular. Your app should recover without losing data.

```typescript
function useRobustWebSocket<T>(url: string) {
  const [messages, setMessages] = useState<T[]>([]);
  const [connectionState, setConnectionState] = useState<
    "connecting" | "connected" | "disconnected"
  >("connecting");
  const pendingMessages = useRef<T[]>([]);

  const { isConnected, sendMessage, lastMessage } = useWebSocket<T>({
    url,
    reconnectAttempts: Infinity,
    reconnectInterval: 2000,
    onMessage: (data) => {
      setMessages((prev) => [...prev, data]);
    },
  });

  // Track connection state
  useEffect(() => {
    setConnectionState(isConnected ? "connected" : "disconnected");
  }, [isConnected]);

  // Queue messages when disconnected
  const sendWithQueue = useCallback(
    (data: T) => {
      if (isConnected) {
        sendMessage(data);
      } else {
        pendingMessages.current.push(data);
      }
    },
    [isConnected, sendMessage],
  );

  // Send queued messages when connection restores
  useEffect(() => {
    if (isConnected && pendingMessages.current.length > 0) {
      pendingMessages.current.forEach((msg) => sendMessage(msg));
      pendingMessages.current = [];
    }
  }, [isConnected, sendMessage]);

  return {
    messages,
    connectionState,
    sendMessage: sendWithQueue,
    queuedCount: pendingMessages.current.length,
  };
}
```

