# Type-Safe State Management: Beyond useContext

We've all been there a typo in an action name sends you debugging for an hour. Or worse, you accidentally mutate state and React doesn't re-render. TypeScript prevents these issues, but only if you structure state correctly.

Here's how to build state management that's impossible to misuse.

---

## Pattern 1: Typed Reducers with useReducer

Plain useState works, but useReducer with TypeScript is where magic happens:

```typescript
type State = {
  user: User | null;
  isLoading: boolean;
  error: string | null;
};

type Action =
  | { type: "FETCH_START" }
  | { type: "FETCH_SUCCESS"; payload: User }
  | { type: "FETCH_ERROR"; payload: string };

const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "FETCH_START":
      return { ...state, isLoading: true, error: null };
    case "FETCH_SUCCESS":
      return { ...state, isLoading: false, user: action.payload };
    case "FETCH_ERROR":
      return { ...state, isLoading: false, error: action.payload };
    default:
      return state;
  }
};

// Usage
const [state, dispatch] = useReducer(reducer, initialState);
dispatch({ type: "FETCH_SUCCESS", payload: user }); // ✅ Type-safe
dispatch({ type: "FETCH_SUCCESS" }); // ❌ Error: payload missing
```

**Why it works:** Actions are discriminated unions. TypeScript knows exactly what payload belongs with which action.

---

## Pattern 2: Type-Safe Context with Generics

Context is great but easy to misuse. Here's the pattern I use:

```typescript
interface AuthContextType {
  user: User | null;
  login: (email: string, password: string) => Promise<void>;
  logout: () => void;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider = ({ children }: { children: React.ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const login = async (email: string, password: string) => {
    setIsLoading(true);
    try {
      const user = await api.login(email, password);
      setUser(user);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
};

// Custom hook with built-in error handling
export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context; // Return type is AuthContextType
};

// Usage
const { user, login } = useAuth(); // ✅ Type-safe, no undefined checks needed
```

**Key insight:** The custom hook guarantees context exists, eliminating runtime errors.

---

## Pattern 3: Zustand with TypeScript (My Current Favorite)

Zustand is simpler than Redux but more flexible than Context:

```typescript
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

interface CartStore {
  items: CartItem[];
  total: number;
  addItem: (item: CartItem) => void;
  removeItem: (id: string) => void;
  clearCart: () => void;
}

const useCartStore = create<CartStore>()(
  persist(
    (set, get) => ({
      items: [],
      total: 0,

      addItem: (item) => {
        const currentItems = get().items;
        const existing = currentItems.find(i => i.id === item.id);

        if (existing) {
          // Update quantity if exists
          set({
            items: currentItems.map(i =>
              i.id === item.id
                ? { ...i, quantity: i.quantity + 1 }
                : i
            )
          });
        } else {
          // Add new item
          set({ items: [...currentItems, { ...item, quantity: 1 }] });
        }

        // Recalculate total
        set({ total: calculateTotal(get().items) });
      },

      removeItem: (id) => set((state) => ({
        items: state.items.filter(i => i.id !== id),
        total: calculateTotal(state.items.filter(i => i.id !== id))
      })),

      clearCart: () => set({ items: [], total: 0 })
    }),
    { name: 'cart-storage' } // Persists to localStorage
  )
);

// Usage in component
const Cart = () => {
  const { items, total, addItem, removeItem } = useCartStore();

  return (
    <div>
      {items.map(item => (
        <div key={item.id}>
          {item.name} x{item.quantity}
          <button onClick={() => removeItem(item.id)}>Remove</button>
        </div>
      ))}
      <div>Total: ${total}</div>
    </div>
  );
};
```

**Why Zustand wins:**

- No providers needed
- Built-in devtools and persistence
- TypeScript inference works perfectly
- Selectors prevent unnecessary re-renders

---

## Pattern 4: Selectors for Performance

With any state solution, selectors prevent over-rendering:

```typescript
// With Zustand
const userName = useCartStore((state) => state.user?.name); // Only re-renders when name changes

// Custom selector hook
const useCartItem = (id: string) => {
  return useCartStore((state) => state.items.find((item) => item.id === id));
};

// With Context + useMemo
const useFilteredTodos = (filter: FilterType) => {
  const { todos } = useTodoContext();

  return useMemo(() => {
    return todos.filter((todo) => {
      if (filter === "active") return !todo.completed;
      if (filter === "completed") return todo.completed;
      return true;
    });
  }, [todos, filter]);
};
```

